const input = $('Edit Fields').first().json.message;
const cleanInput = input && input.length > 25 ? input.substring(0, 25) + '...' : input;

return {
  response_message:
    `Not sure what you mean by "${cleanInput}". ` +
    `I can help you place a cake order or answer questions about our bakery. What would you like to do?`
};

return {
  response_message:
    `Your order has been cancelled.\n\n` +
    `If you change your mind or want to start fresh, just send us a message anytime.`
};

// 1. Constructing the Human Handoff Message
let finalMessage = `Hi, I've notified our baking team that you'd like to chat! \n\n` +
    `A human team member will jump in here as soon as possible to help you out.`;

return {
    response_message: finalMessage
};

const orders = $input.all() || []; 
let orderList = "";

const statusMap = {
    'DRAFT': '📝 Draft',
    'AWAITING_APPROVAL': '⏳ Pending Approval',
    'AWAITING_DEPOSIT': '💳 Awaiting Deposit',
    'AWAITING_REVIEW': '🧐 Under Review',
    'COMPLETED': '✅ Completed'
};

if (orders.length > 0) {
    orders.forEach((item, index) => {
        const order = item.json.selections;
        const statusKey = item.json.order_status_id;
        const statusText = statusMap[statusKey] || statusKey;

        const displayDate = order.event_date 
            ? new Date(order.event_date).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) 
            : "Date TBD";

        // 1. Format Tier Details (Size, Flavor, Layers)
        let tierSummary = "";
        if (order.tier_definitions && Array.isArray(order.tier_definitions)) {
            tierSummary = order.tier_definitions.map(t => 
                `   🔹 T${t.tier_index}: ${t.size}" ${t.flavor} (${t.layers} layers)`
            ).join('\n');
        } else {
            tierSummary = "   🔹 Details TBD";
        }

        // 2. Build the Block
        orderList += `${index + 1}. *${order.cake_theme || 'Custom Cake'}* (${statusText})\n` +
                     `   📅 ${displayDate}\n` +
                     `${tierSummary}\n\n`;
    });
} else {
    orderList = "No active orders found! 🧁";
}

let finalMessage = `📋 *YOUR ORDER STATUS* 📋\n\n` +
    `Hi there! Here is the breakdown of your current cake projects:\n\n` +
    `${orderList}` +
    `--- --- --- --- --- --- ---\n` +
    ``;

return {
    response_message: finalMessage
};

let message = `✨ *User would like to talk to a Human* ✨` +
  $('Edit Fields').first().json.customer_id
return {
    response_message: message
};
